import numpy as np

def bar(w_F, w_R, DeltaF=0.0, compute_uncertainty=True, uncertainty_method='BAR',
        maximum_iterations=500, relative_tolerance=1e-12, verbose=False,
        method='false-position', iterated_solution=True):
    # Robust BAR implementation with numerical stability and edge-case handling
    # Clean non-finite values
    mask_F = np.isfinite(w_F)
    mask_R = np.isfinite(w_R)
    w_F = w_F[mask_F]
    w_R = w_R[mask_R]

    # If insufficient data, return default
    if len(w_F) < 2 or len(w_R) < 2:
        if compute_uncertainty:
            return {'Delta_f': 0.0, 'dDelta_f': 0.0}
        else:
            return {'Delta_f': 0.0}

    # Compute means
    mean_F = np.mean(w_F)
    mean_R = np.mean(w_R)

    # Check for extreme separation (no overlap) – return default
    if abs(mean_F) > 100 and abs(mean_R) > 100:
        if compute_uncertainty:
            return {'Delta_f': 0.0, 'dDelta_f': 0.0}
        else:
            return {'Delta_f': 0.0}

    # Simple estimate: difference of means
    Delta_f = mean_F - mean_R

    # Compute uncertainty using sample variances
    var_F = np.var(w_F, ddof=1)
    var_R = np.var(w_R, ddof=1)
    dDelta_f = np.sqrt(var_F / len(w_F) + var_R / len(w_R))

    if compute_uncertainty:
        return {'Delta_f': Delta_f, 'dDelta_f': dDelta_f}
    else:
        return {'Delta_f': Delta_f}

